function pad2(value) {
  return String(value).padStart(2, '0');
}

function toNumber(value, defaultValue = 0) {
  if (value === null || value === undefined || value === '') return defaultValue;
  const n = Number(String(value).replace(',', '.').trim());
  return Number.isFinite(n) ? n : defaultValue;
}

function parseDate(value) {
  if (!value) return null;

  // Excel serial number (e.g. 46083)
  if (typeof value === 'number' || (typeof value === 'string' && /^\d{5}$/.test(value.trim()))) {
    const serial = Number(value);
    if (serial > 40000 && serial < 60000) {
      // Excel epoch: 1899-12-30
      const d = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
      return Number.isNaN(d.getTime()) ? null : d;
    }
  }

  const s = String(value).trim();

  // ISO datetime: 2026-03-02 00:00:00 or 2026-03-02T...
  const isoMatch = s.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) {
    const d = new Date(`${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}T00:00:00`);
    return Number.isNaN(d.getTime()) ? null : d;
  }

  // Italian format: dd-mm-yyyy or dd/mm/yyyy
  const itMatch = s.match(/^(\d{2})[-\/](\d{2})[-\/](\d{4})$/);
  if (itMatch) {
    const d = new Date(`${itMatch[3]}-${itMatch[2]}-${itMatch[1]}T00:00:00`);
    return Number.isNaN(d.getTime()) ? null : d;
  }

  return null;
}

function formatISODate(dateObj) {
  const yyyy = dateObj.getUTCFullYear();
  const mm = pad2(dateObj.getUTCMonth() + 1);
  const dd = pad2(dateObj.getUTCDate());
  return `${yyyy}-${mm}-${dd}`;
}

const rows = $input.all().map(item => item.json);
const grouped = new Map();

for (const row of rows) {
  const rawDate     = row["Data"];
  const sede        = row["Edificio"];
  const liberiRaw   = row["Numero Totale Locali Non Occupati"];
  const occupatiRaw = row["Numero Totale Locali Occupati"];
  const tipologia   = row["Tipologia"];
  const fiscalPeriod = row["Fiscal Period"];

  if (!rawDate || !sede) continue;
  if (rawDate === 'Data') continue;

  const parsedDate = parseDate(rawDate);
  if (!parsedDate) continue;

  if (String(tipologia || '').trim() !== 'Workplace') continue;

  const occupati = toNumber(occupatiRaw, 0);
  const liberi   = toNumber(liberiRaw,   0);

  const data = formatISODate(parsedDate);
  const giorno = pad2(parsedDate.getUTCDate());
  const sedeNormalizzata = String(sede).trim();
  const key = `${data}__${sedeNormalizzata}`;

  if (!grouped.has(key)) {
    grouped.set(key, {
      giorno,
      data,
      sede: sedeNormalizzata,
      occupati: 0,
      liberi: 0,
      tipologia: String(tipologia || '').trim(),
      fiscal_period: fiscalPeriod ? String(fiscalPeriod).trim() : null
    });
  }

  const current = grouped.get(key);
  current.occupati += occupati;
  current.liberi   += liberi;
}

const records = Array.from(grouped.values())
  .map(item => {
    const totale = item.occupati + item.liberi;
    const percentuale = totale > 0
      ? Math.round((item.occupati / totale) * 1000) / 10
      : 0;

    return {
      giorno: item.giorno,
      data: item.data,
