// Mappa principale sensori
const SENSOR_MAP = {
  TOTAL_POWER: 'TOTAL_POWER',
  CANTEEN_POWER: 'CANTEEN_POWER',
  FV_POWER: 'FV_POWER',
  HEAT_POWER: 'HEAT_POWER',
  CAR_CHARGER: 'CAR_CHARGER',
};

