  '04B201': 'TOTAL_POWER',
  '04B301': 'CANTEEN_POWER',
  'FFFE03': 'FV_POWER',
  'FFFE02': 'HEAT_POWER',
  'FFFE01': 'CAR_CHARGER',
};

function normalizeText(value) {
  return String(value ?? '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '');
}

function parseNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;

  let s = String(value).trim();
  if (!s) return null;

  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }

  const n = parseFloat(s);
  return Number.isFinite(n) ? n : null;
}

function parseJsonSafe(str) {
  try {
    return JSON.parse(String(str).trim());
  } catch {
    return null;
  }
}

function findBodyString(row) {
  const direct = row.Body ?? row.body ?? row.BODY ?? null;
  if (typeof direct === 'string' && direct.trim().startsWith('{')) return direct.trim();

  for (const value of Object.values(row)) {
    if (typeof value !== 'string') continue;
    const v = value.trim();
    if (!v.startsWith('{')) continue;
    if (
      v.includes('"items"') ||
      v.includes('"devices"') ||
      v.includes('"hn"') ||
      v.includes('"sn"')
    ) {
      return v;
    }
  }

  return null;
}

function getCanonicalSn(device) {
  const sn = String(device?.sn ?? '').trim();
