  if (SENSOR_MAP[sn]) return SENSOR_MAP[sn];
  if (LI_TO_SN[li]) return LI_TO_SN[li];

  return null;
}

function isPositiveEnergyMeasure(measure) {
  const name = normalizeText(measure?.iName);
  if (!name) return false;

  if (name.includes('rea')) return false;
  if (name.includes('reatt')) return false;
  if (name.includes('react')) return false;

  if (name === 'energiaattivapositiva') return true;
  if (name === 'energiatrifaseattpositiva') return true;

  return name.includes('energia') && name.includes('positiva');
}

function pickEnergyMeasure(ms) {
  if (!Array.isArray(ms) || ms.length === 0) return null;

  const exact = ms.find(isPositiveEnergyMeasure);
  if (exact) return exact;

  const soft = ms.find(m => {
    const name = normalizeText(m?.iName);
    return name.includes('energia') && !name.includes('rea') && !name.includes('reatt');
  });
  if (soft) return soft;

  return null;
}

function pickTimestamp(payload, device, energyMeasure) {
  return (
    energyMeasure?.ts ||
    (Array.isArray(device?.ms) && device.ms.find(m => m?.ts)?.ts) ||
    payload?.ts ||
    new Date().toISOString()
  );
}

// Pulisce e regolarizza il timestamp all'ora piena:
// - minuti 00-29 => stessa ora :00
// - minuti 30-59 => ora successiva :00
function normalizeTimestamp(rawTs) {
  if (rawTs === null || rawTs === undefined || rawTs === '') {
    return new Date().toISOString();
  }

  let s = String(rawTs).trim();

  // pulizia base
  s = s
    .replace(/\//g, '-')              // 2026/03/25 -> 2026-03-25
    .replace(' ', 'T')                // 2026-03-25 10:15:00 -> 2026-03-25T10:15:00
    .replace(/\.\d+Z$/, 'Z')          // rimuove millisecondi eccessivi finali se presenti
    .replace(/\.\d+$/, '');           // rimuove millisecondi senza Z

  let d = new Date(s);

  // fallback semplice per formati non perfetti
  if (isNaN(d.getTime())) {
    const alt = s.replace('T', ' ');
    d = new Date(alt);
  }

  if (isNaN(d.getTime())) {
    return new Date().toISOString();
  }

  const minutes = d.getMinutes();

  // azzera minuti/secondi/ms
  d.setMinutes(0, 0, 0);

  // se da 30 a 59, porta all'ora successiva
  if (minutes >= 30) {
    d.setHours(d.getHours() + 1);
  }

  return d.toISOString();
}

