  recs.sort((a, b) => a.ts - b.ts);

  const deduped = [];
  for (const rec of recs) {
    const prev = deduped[deduped.length - 1];
    if (prev && prev.ts.getTime() === rec.ts.getTime()) {
      deduped[deduped.length - 1] = rec;
    } else {
      deduped.push(rec);
    }
  }

  bySensor.set(sn, deduped);
}

// ---------------------------------------------------------
// 3) Accesso efficiente ai valori "ultimo <= ts"
// ---------------------------------------------------------
function latestBeforeOrAt(sn, ts) {
  const recs = bySensor.get(sn) || [];
  if (recs.length === 0) return null;

  let lo = 0;
  let hi = recs.length - 1;
  let ans = -1;
  const target = ts.getTime();

  while (lo <= hi) {
    const mid = Math.floor((lo + hi) / 2);
    const t = recs[mid].ts.getTime();

    if (t <= target) {
      ans = mid;
      lo = mid + 1;
    } else {
      hi = mid - 1;
    }
  }

  return ans >= 0 ? recs[ans] : null;
}

function latestBeforeWithin(sn, ts, maxAgeMs) {
  const rec = latestBeforeOrAt(sn, ts);
  if (!rec) return null;
  if ((ts.getTime() - rec.ts.getTime()) > maxAgeMs) return null;
  return rec;
}

function deltaKwh(sn, fromTs, toTs, options = {}) {
  const {
    maxGapMs = null,
    allowNegative = false,
  } = options;

  const start = maxGapMs === null
    ? latestBeforeOrAt(sn, fromTs)
    : latestBeforeWithin(sn, fromTs, maxGapMs);

  const end = maxGapMs === null
    ? latestBeforeOrAt(sn, toTs)
    : latestBeforeWithin(sn, toTs, maxGapMs);

  if (!start || !end) return 0;

  let delta = end.energy_kwh - start.energy_kwh;

  if (delta < 0 && !allowNegative) return 0;
  if (Math.abs(delta) < 0.0001) return 0;

  return delta;
}

