function buildTotals(fromTs, toTs, maxGapMs) {
  return {
    consumo: round0(deltaKwh('TOTAL_POWER', fromTs, toTs, { maxGapMs })),
    fotovoltaico: round0(deltaKwh('FV_POWER', fromTs, toTs, { maxGapMs })),
  };
}

function buildTotalSeries(slots, maxGapMs) {
  return slots.map(sl => ({
    label: sl.label,
    value: round0(deltaKwh('TOTAL_POWER', sl.s, sl.e, { maxGapMs })),
  }));
}

function buildPartialSeries(slots, maxGapMs) {
  const labels = slots.map(sl => sl.label);
  const series = {};

  // Serie sensori fisici
  for (const sensor of PARTIAL_SERIES) {
    series[sensor.label] = slots.map(sl =>
      round0(deltaKwh(sensor.sn, sl.s, sl.e, { maxGapMs }))
    );
  }

  // Consumo Edificio = Totale - Frigo - Mensa - Auto (≥ 0 per slot)
  series['Consumo Edificio'] = slots.map((sl, i) => {
    const totale = round0(deltaKwh('TOTAL_POWER', sl.s, sl.e, { maxGapMs }));
    const sottratti = PARTIAL_SERIES.reduce((sum, sensor) =>
      sum + (series[sensor.label][i] || 0), 0
    );
    return Math.max(0, totale - sottratti);
  });

  return { labels, series };
}

function sumSeriesValues(series) {
  return round0(series.reduce((sum, item) => sum + Number(item.value || 0), 0));
}

function sumSensorAcrossSlots(slots, sn, maxGapMs) {
  return round0(
    slots.reduce((sum, sl) => sum + deltaKwh(sn, sl.s, sl.e, { maxGapMs }), 0)
  );
}

