  const cName=CLASSE_SHORT[classe]||classe;
  if(!corrMap[pName]) corrMap[pName]={value:0,children:{}};
  corrMap[pName].value++;
  corrMap[pName].children[cName]=(corrMap[pName].children[cName]||0)+1;
}
const corrItems=Object.entries(corrMap)
  .map(([name,d])=>({name,value:d.value,
    children:Object.entries(d.children).map(([n,v])=>({name:n,value:v})).sort((a,b)=>b.value-a.value)}))
  .sort((a,b)=>b.value-a.value);

// ── Period label from Baseline date range ─────────────────────────────────────
const allDates=rows.map(r=>parseDate(r['Baseline Inizio'])).filter(Boolean).sort((a,b)=>a-b);
let periodLabel='';
if(allDates.length){
  const m1=allDates[0].getMonth()+1, m2=allDates[allDates.length-1].getMonth()+1;
  const yr=allDates[allDates.length-1].getFullYear();
  periodLabel=m1===m2?MONTHS_IT[m1]+' '+yr:MONTHS_IT[m1]+' – '+MONTHS_IT[m2]+' '+yr;
}

const result={
  updated_at:fmt(),
  period_label:periodLabel,
  kpi:{total,completed,sla_on_time_pct:slaPct,active,late},
  sede:[
    {name:'Roma', completed:sedeMap.Roma.completed, active:sedeMap.Roma.active, late:sedeMap.Roma.late},
    {name:'Milano', completed:sedeMap.Milano.completed, active:sedeMap.Milano.active, late:sedeMap.Milano.late}
  ],
  trend:{
    dates:trendSorted.map(e=>e[0]),
    values:trendSorted.map(e=>e[1])
  },
  programmate:progItems,
  correttive:{
    total:corrItems.reduce((s,i)=>s+i.value,0),
    items:corrItems
  }
};

return[{json:{filename:'data/data_tasks.json',
  base64Content:Buffer.from(JSON.stringify(result,null,2)).toString('base64')}}];
